      const result = defaultSoulTemplate('test-bot', 'trait-block');
      expect(result).toContain(TRAIT_SECTION_START);
      expect(result).toContain(TRAIT_SECTION_END);
    });

    it('includes default values section', () => {
      const result = defaultSoulTemplate('test-bot', 'trait-block');
